import os
from datetime import datetime, timezone
from functools import wraps

from flask import Flask, request, jsonify, g
from pymongo import MongoClient, ASCENDING, DESCENDING
from pymongo.errors import ConnectionFailure, OperationFailure
from bson import ObjectId, json_util
from werkzeug.security import generate_password_hash, check_password_hash
import json
import secrets

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', secrets.token_hex(32))

# MongoDB configuration - require authentication
MONGO_HOST = os.environ.get('MONGO_HOST', 'localhost')
MONGO_PORT = int(os.environ.get('MONGO_PORT', 27017))
MONGO_DB = os.environ.get('MONGO_DB', 'cms_database')
MONGO_USERNAME = os.environ.get('MONGO_USERNAME', 'cms_admin')
MONGO_PASSWORD = os.environ.get('MONGO_PASSWORD', 'cms_secure_password_123')
MONGO_AUTH_SOURCE = os.environ.get('MONGO_AUTH_SOURCE', 'admin')


def get_mongo_client():
    """Create MongoDB client with authentication enforced."""
    if not MONGO_USERNAME or not MONGO_PASSWORD:
        raise OperationFailure(
            "MongoDB authentication credentials are required. "
            "Set MONGO_USERNAME and MONGO_PASSWORD environment variables."
        )

    connection_uri = (
        f"mongodb://{MONGO_USERNAME}:{MONGO_PASSWORD}"
        f"@{MONGO_HOST}:{MONGO_PORT}/{MONGO_DB}"
        f"?authSource={MONGO_AUTH_SOURCE}"
        f"&authMechanism=SCRAM-SHA-256"
    )

    client = MongoClient(
        connection_uri,
        serverSelectionTimeoutMS=5000,
        connectTimeoutMS=5000,
        socketTimeoutMS=5000,
        maxPoolSize=50,
        retryWrites=True,
    )

    # Verify the connection and authentication
    try:
        client.admin.command('ping')
    except ConnectionFailure as e:
        raise ConnectionFailure(f"Failed to connect to MongoDB: {e}")
    except OperationFailure as e:
        raise OperationFailure(f"MongoDB authentication failed: {e}")

    return client


def get_db():
    """Get database connection from application context."""
    if 'db' not in g:
        g.client = get_mongo_client()
        g.db = g.client[MONGO_DB]
    return g.db


@app.teardown_appcontext
def close_db(exception):
    """Close database connection on teardown."""
    client = g.pop('client', None)
    if client is not None:
        client.close()
    g.pop('db', None)


def parse_json(data):
    """Parse MongoDB BSON to JSON-serializable format."""
    return json.loads(json_util.dumps(data))


def sanitize_input(value):
    """Sanitize input to prevent NoSQL injection."""
    if isinstance(value, dict):
        sanitized = {}
        for k, v in value.items():
            if isinstance(k, str) and k.startswith('$'):
                raise ValueError(f"Invalid key: operator keys not allowed in user input: {k}")
            sanitized[k] = sanitize_input(v)
        return sanitized
    elif isinstance(value, list):
        return [sanitize_input(item) for item in value]
    elif isinstance(value, str):
        # Strip any embedded operators
        if value.startswith('$'):
            raise ValueError(f"Invalid value: operator values not allowed in user input: {value}")
        return value
    return value


# --- API Token Authentication ---

def require_auth(f):
    """Decorator to require API token authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Authorization header with Bearer token required'}), 401

        token = auth_header.split('Bearer ')[1]
        db = get_db()
        session = db.sessions.find_one({
            'token': token,
            'expires_at': {'$gt': datetime.now(timezone.utc)}
        })

        if not session:
            return jsonify({'error': 'Invalid or expired token'}), 401

        user = db.users.find_one({'_id': session['user_id']})
        if not user:
            return jsonify({'error': 'User not found'}), 401

        g.current_user = user
        return f(*args, **kwargs)
    return decorated_function


def require_role(*roles):
    """Decorator to require specific user roles."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            if not hasattr(g, 'current_user') or g.current_user is None:
                return jsonify({'error': 'Authentication required'}), 401
            user_role = g.current_user.get('role', 'viewer')
            if user_role not in roles:
                return jsonify({'error': 'Insufficient permissions'}), 403
            return f(*args, **kwargs)
        return decorated_function
    return decorator


