@app.route('/api/auth/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    required_fields = ['username', 'email', 'password']
    for field in required_fields:
        if field not in data:
            return jsonify({'error': f'Missing required field: {field}'}), 400

    try:
        sanitize_input({'username': data['username'], 'email': data['email']})
    except ValueError as e:
        return jsonify({'error': str(e)}), 400

    if len(data['password']) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400

    db = get_db()

    # Check for existing user
    existing = db.users.find_one({
        '$or': [
            {'username': data['username']},
            {'email': data['email']}
        ]
    })
    if existing:
        return jsonify({'error': 'Username or email already exists'}), 409

    profile = data.get('profile', {})
    try:
        profile = sanitize_input(profile)
    except ValueError as e:
        return jsonify({'error': str(e)}), 400

    user_doc = {
        'username': data['username'],
        'email': data['email'],
        'password_hash': generate_password_hash(data['password']),
        'role': 'viewer',  # Default role; admin must promote
        'profile': {
            'first_name': profile.get('first_name', ''),
            'last_name': profile.get('last_name', ''),
            'bio': profile.get('bio', ''),
            'avatar_url': profile.get('avatar_url', ''),
        },
        'created_at': datetime.now(timezone.utc),
        'updated_at': datetime.now(timezone.utc),
        'is_active': True,
    }

    result = db.users.insert_one(user_doc)
    user_doc['_id'] = result.inserted_id

    return jsonify({
        'message': 'User registered successfully',
        'user': parse_json({
            '_id': user_doc['_id'],
            'username': user_doc['username'],
            'email': user_doc['email'],
            'role': user_doc['role'],
            'profile': user_doc['profile'],
        })
    }), 201


@app.route('/api/auth/login', methods=['POST'])
def login():
    """Authenticate user and return a session token."""
    data = request.get_json()
    if not data or 'username' not in data or 'password' not in data:
        return jsonify({'error': 'Username and password required'}), 400

    try:
        sanitize_input({'username': data['username']})
    except ValueError as e:
        return jsonify({'error': str(e)}), 400

    db = get_db()
    user = db.users.find_one({'username': data['username']})

    if not user or not check_password_hash(user['password_hash'], data['password']):
        return jsonify({'error': 'Invalid credentials'}), 401

    if not user.get('is_active', True):
        return jsonify({'error': 'Account is deactivated'}), 403

    # Create session token
    token = secrets.token_hex(32)
    session_doc = {
        'token': token,
        'user_id': user['_id'],
        'created_at': datetime.now(timezone.utc),
        'expires_at': datetime(2099, 12, 31, tzinfo=timezone.utc),  # Long-lived for demo; use shorter in production
    }
    # Set a more reasonable expiry: 24 hours
    from datetime import timedelta
    session_doc['expires_at'] = datetime.now(timezone.utc) + timedelta(hours=24)

    db.sessions.insert_one(session_doc)

    return jsonify({
        'message': 'Login successful',
        'token': token,
        'user': parse_json({
            '_id': user['_id'],
            'username': user['username'],
            'role': user['role'],
        })
    }), 200


@app.route('/api/auth/logout', methods=['POST'])
@require_auth
def logout():
    """Invalidate the current session token."""
    auth_header = request.headers.get('Authorization')
    token = auth_header.split('Bearer ')[1]
    db = get_db()
    db.sessions.delete_one({'token': token})
    return jsonify({'message': 'Logged out successfully'}), 200


