@app.route('/api/documents', methods=['POST'])
@require_auth
@require_role('admin', 'editor', 'author')
def create_document():
    """Create a new document."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    required_fields = ['title', 'content']
    for field in required_fields:
        if field not in data:
            return jsonify({'error': f'Missing required field: {field}'}), 400

    try:
        sanitize_input({
            'title': data['title'],
            'category': data.get('category', ''),
        })
        if 'tags' in data:
            sanitize_input(data['tags'])
    except ValueError as e:
        return jsonify({'error': str(e)}), 400

    db = get_db()
    doc = {
        'title': data['title'],
        'content': data['content'],
        'summary': data.get('summary', ''),
        'category': data.get('category', 'uncategorized'),
        'tags': data.get('tags', []),
        'status': data.get('status', 'draft'),  # draft, published, archived
        'author_id': g.current_user['_id'],
        'author_username': g.current_user['username'],
        'metadata': data.get('metadata', {}),
        'version': 1,
        'created_at': datetime.now(timezone.utc),
        'updated_at': datetime.now(timezone.utc),
        'published_at': None,
    }

    # Validate status
    valid_statuses = ['draft', 'published', 'archived']
    if doc['status'] not in valid_statuses:
        return jsonify({'error': f'Invalid status. Must be one of: {valid_statuses}'}), 400

    if doc['status'] == 'published':
        doc['published_at'] = datetime.now(timezone.utc)

    result = db.documents.insert_one(doc)
    doc['_id'] = result.inserted_id

    return jsonify({
        'message': 'Document created successfully',
        'document': parse_json(doc)
    }), 201


@app.route('/api/documents', methods=['GET'])
@require_auth
def list_documents():
    """List documents with filtering, sorting, and pagination."""
    db = get_db()

    page = max(1, request.args.get('page', 1, type=int))
    per_page = min(100, max(1, request.args.get('per_page', 20, type=int)))
    skip = (page - 1) * per_page

    query = {}

    # Status filter
    status = request.args.get('status')
    if status and status in ['draft', 'published', 'archived']:
        query['status'] = status
    elif g.current_user.get('role') == 'viewer':
        # Viewers can only see published documents
        query['status'] = 'published'

    # Category filter
    category = request.args.get('category')
    if category:
        try:
            sanitize_input({'category': category})
            query['category'] = category
        except ValueError:
            return jsonify({'error': 'Invalid category value'}), 400

    # Tag filter
    tag = request.args.get('tag')
    if tag:
        try:
            sanitize_input({'tag': tag})
            query['tags'] = tag
        except ValueError:
            return jsonify({'error': 'Invalid tag value'}), 400

    # Author filter
    author_id = request.args.get('author_id')
    if author_id:
        try:
            query['author_id'] = ObjectId(author_id)
        except Exception:
            return jsonify({'error': 'Invalid author ID'}), 400

    # Text search
    search = request.args.get('search')
    if search:
        try:
            sanitize_input({'search': search})
            query['$text'] = {'$search': search}
        except ValueError:
            return jsonify({'error': 'Invalid search value'}), 400

    # If author role, only show own documents (unless published)
    if g.current_user.get('role') == 'author':
        query['$or'] = [
            {'author_id': g.current_user['_id']},
            {'status': 'published'}
        ]

    # Sorting
    sort_field = request.args.get('sort', 'created_at')
    sort_order = DESCENDING if request.args.get('order', 'desc') == 'desc' else ASCENDING
    allowed_sort_fields = ['created_at', 'updated_at', 'title', 'published_at']
    if sort_field not in allowed_sort_fields:
        sort_field = 'created_at'

    total = db.documents.count_documents(query)
    documents = db.documents.find(query).sort(sort_field, sort_order).skip(skip).limit(per_page)

    return jsonify({
        'documents': parse_json(list(documents)),
        'pagination': {
            'page': page,
            'per_page': per_page,
            'total': total,
            'pages': (total + per_page - 1) // per_page,
        }
    }), 200


@app.route('/api/documents/<doc_id>', methods=['GET'])
@require_auth
def get_document(doc_id):
    """Get a specific document."""
    try:
        oid = ObjectId(doc_id)
    except Exception:
        return jsonify({'error': 'Invalid document ID'}), 400

    db = get_db()
    doc = db.documents.find_one({'_id': oid})

    if not doc:
        return jsonify({'error': 'Document not found'}), 404

    # Viewers can only see published documents
    if g.current_user.get('role') == 'viewer' and doc.get('status') != 'published':
        return jsonify({'error': 'Document not found'}), 404

    # Authors can only see their own unpublished documents
    if (g.current_user.get('role') == 'author'
            and doc.get('status') != 'published'
            and doc.get('author_id') != g.current_user['_id']):
        return jsonify({'error': 'Document not found'}), 404

    return jsonify({'document': parse_json(doc)}), 200


@app.route('/api/documents/<doc_id>', methods=['PUT'])
@require_auth
@require_role('admin', 'editor', 'author')
def update_document(doc_id):
    """Update a document."""
    try:
        oid = ObjectId(doc_id)
    except Exception:
        return jsonify({'error': 'Invalid document ID'}), 400

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    try:
        sanitize_input(data)
    except ValueError as e:
        return jsonify({'error': str(e)}), 400

    db = get_db()
    doc = db.documents.find_one({'_id': oid})

    if not doc:
        return jsonify({'error': 'Document not found'}), 404

    # Authors can only update their own documents
    if (g.current_user.get('role') == 'author'
            and doc.get('author_id') != g.current_user['_id']):
        return jsonify({'error': 'Permission denied'}), 403

    update_fields = {'updated_at': datetime.now(timezone.utc)}

    allowed_fields = ['title', 'content', 'summary', 'category', 'tags', 'status', 'metadata']
    for field in allowed_fields:
        if field in data:
            update_fields[field] = data[field]

    # Validate status
    if 'status' in update_fields:
        valid_statuses = ['draft', 'published', 'archived']
        if update_fields['status'] not in valid_statuses:
            return jsonify({'error': f'Invalid status. Must be one of: {valid_statuses}'}), 400
        if update_fields['status'] == 'published' and doc.get('status') != 'published':
            update_fields['published_at'] = datetime.now(timezone.utc)

    # Increment version
    update_fields['version'] = doc.get('version', 1) + 1

    result = db.documents.update_one(
        {'_id': oid},
        {'$set': update_fields}
    )

    updated_doc = db.documents.find_one({'_id': oid})
    return jsonify({
        'message': 'Document updated successfully',
        'document': parse_json(updated_doc)
    }), 200


