@app.route('/api/analytics/content-summary', methods=['GET'])
@require_auth
@require_role('admin', 'editor')
def content_summary():
    """Get overall content management summary using aggregation."""
    db = get_db()

    # Documents summary
    doc_pipeline = [
        {'$facet': {
            'total': [{'$count': 'count'}],
            'by_status': [
                {'$group': {'_id': '$status', 'count': {'$sum': 1}}}
            ],
            'by_category': [
                {'$group': {'_id': '$category', 'count': {'$sum': 1}}},
                {'$sort': {'count': -1}},
                {'$limit': 10}
            ],
            'recent': [
                {'$sort': {'created_at': -1}},
                {'$limit': 5},
                {'$project': {
                    'title': 1,
                    'status': 1,
                    'author_username': 1,
                    'created_at': 1,
                }}
            ],
            'avg_content_length': [
                {'$project': {'content_length': {'$strLenCP': '$content'}}},
                {'$group': {'_id': None, 'avg_length': {'$avg': '$content_length'}}}
            ]
        }}
    ]

    doc_results = list(db.documents.aggregate(doc_pipeline))

    # Users summary
    user_count = db.users.count_documents({'is_active': True})

    summary = {
        'documents': parse_json(doc_results[0] if doc_results else {}),
        'active_users': user_count,
    }

    return jsonify({'summary': summary}), 200


# --- Advanced Query Routes ---

@app.route('/api/documents/search', methods=['POST'])
@require_auth
def advanced_search():
    """Advanced document search with complex queries."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    try:
        sanitize_input(data)
    except ValueError as e:
        return jsonify({'error': str(e)}), 400

    db = get_db()
    query = {}

    # Text search
    if 'text' in data:
        query['$text'] = {'$search': data['text']}

    # Date range filter
    if 'date_from' in data or 'date_to' in data:
        date_query = {}
        if 'date_from' in data:
            try:
                date_query['$gte'] = datetime.fromisoformat(data['date_from'])
            except ValueError:
                return jsonify({'error': 'Invalid date_from format. Use ISO format.'}), 400
        if 'date_to' in data:
            try:
                date_query['$lte'] = datetime.fromisoformat(data['date_to'])
            except ValueError:
                return jsonify({'error': 'Invalid date_to format. Use ISO format.'}), 400
        if date_query:
            query['created_at'] = date_query

    # Status filter
    if 'statuses' in data and isinstance(data['statuses'], list):
        valid_statuses = ['draft', 'published', 'archived']
        statuses = [s for s in data['statuses'] if s in valid_statuses]
        if statuses:
            query['status'] = {'$in': statuses}

    # Category filter
    if 'categories' in data and isinstance(data['categories'], list):
        query['category'] = {'$in': data['categories']}

    # Tags filter (documents containing ALL specified tags)
    if 'tags_all' in data and isinstance(data['tags_all'], list):
        query['tags'] = {'$all': data['tags_all']}

    # Tags filter (documents containing ANY specified tags)
    if 'tags_any' in data and isinstance(data['tags_any'], list):
        query['tags'] = {'$in': data['tags_any']}

    # Author filter
    if 'author_ids' in data and isinstance(data['author_ids'], list):
        try:
            author_oids = [ObjectId(aid) for aid in data['author_ids']]
            query['author_id'] = {'$in': author_oids}
        except Exception:
            return jsonify({'error': 'Invalid author ID in list'}), 400

    # Viewers restriction
    if g.current_user.get('role') == 'viewer':
        query['status'] = 'published'

    page = max(1, data.get('page', 1))
    per_page = min(100, max(1, data.get('per_page', 20)))
    skip = (page - 1) * per_page

    total = db.documents.count_documents(query)
    documents = db.documents.find(query).sort('created_at', DESCENDING).skip(skip).limit(per_page)

    return jsonify({
        'documents': parse_json(list(documents)),
        'query': parse_json(query),
        'pagination': {
            'page': page,
            'per_page': per_page,
            'total': total,
            'pages': (total + per_page - 1) // per_page,
        }
    }), 200


# --- Health Check ---

@app.route('/api/health', methods=['GET'])
def health_check():
    """Health check endpoint."""
    try:
        client = get_mongo_client()
        client.admin.command('ping')
        client.close()
        db_status = 'connected'
    except Exception as e:
        db_status = f'error: {str(e)}'

    return jsonify({
        'status': 'ok' if db_status == 'connected' else 'degraded',
        'database': db_status,
        'timestamp': datetime.now(timezone.utc).isoformat(),
    }), 200 if db_status == 'connected' else 503


